/// Check if a NER-extracted organization name is a false positive.
/// Validates whether an extracted string is a plausible organization name.
/// Rejects garbage from greedy regex/table extraction: concatenated table rows,
/// strings with embedded country names, table header phrases, etc.
pub fn is_valid_org_name(org_name: &str) -> bool {
    let name = org_name.trim();

    // Too short
    if name.len() < 3 {
        return false;
    }

    // Too long — real org names are rarely > 80 chars
    // e.g. "Amazon Web Services, Inc." = 25 chars
    if name.len() > 80 {
        return false;
    }

    let lower = name.to_lowercase();

    // Contains embedded country/location names that indicate concatenated table rows
    // Real org names don't contain "United States" or "Netherlands" mid-string
    let location_markers = [
        "united states",
        "united kingdom",
        "european union",
        "location of processing",
        "corporate location",
        "description of processing",
        "name of subprocessor",
        "location of sub",
    ];
    for marker in &location_markers {
        if lower.contains(marker) {
            return false;
        }
    }

    // Contains table header/structure phrases
    let table_headers = [
        "third party subprocessors",
        "name of sub",
        "processing location",
        "corporate location",
        "service description",
        "data processed",
        "purpose of processing",
        "categories of data",
        "subsidiaries name",
    ];
    for header in &table_headers {
        if lower.contains(header) {
            return false;
        }
    }

    // Too many words — real org names rarely exceed 6-7 words
    // "Amazon Web Services, Inc." = 4 words
    // "AI Inference and AI Services United States..." = 10+ words → garbage
    let word_count = name.split_whitespace().count();
    if word_count > 8 {
        return false;
    }

    true
}

/// Returns true for patterns that are clearly not real organization names:
/// - ISO 639 language codes (ar, cs, da, de, es, fi, fr, he, hu, id, it, ja, ko, ms, nl, pl, ru, sv, th, tr)
/// - Locale identifiers (en-us, zh-hans, pt-br, nb-no)
/// - Snake_case field/feature names (soc2_report, penetration_testing, encrypt_data)
/// - Very short strings (< 3 chars)
#[cfg_attr(coverage_nightly, coverage(off))]
pub fn is_ner_false_positive(org_name: &str) -> bool {
    let name = org_name.trim();
    let lower = name.to_lowercase();

    // Too short to be a real organization name
    if name.len() < 3 {
        return true;
    }

    // Snake_case identifiers are code/config field names, not organizations
    if lower.contains('_') && lower.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
        return true;
    }

    // Locale/language identifiers (en-us, zh-hans, pt-br, nb-no)
    if lower.len() <= 7
        && lower.contains('-')
        && lower.chars().all(|c| c.is_ascii_alphanumeric() || c == '-')
    {
        return true;
    }

    // Standards, certifications, and regulatory frameworks that NER identifies
    // as organizations but are not vendors (BUG-003/010)
    let standards_and_frameworks = [
        "iso",
        "iec",
        "iso/iec",
        "iso/iec 27001",
        "iso/iec 27017",
        "iso/iec 27018",
        "iso 27001",
        "iso 27017",
        "iso 27018",
        "iso 27701",
        "iso 9001",
        "iso 22301",
        "soc",
        "soc 1",
        "soc 2",
        "soc 3",
        "soc2",
        "soc1",
        "soc3",
        "pci-dss",
        "pci dss",
        "pci",
        "gdpr",
        "ccpa",
        "cpra",
        "hipaa",
        "hitech",
        "ferpa",
        "coppa",
        "glba",
        "nist",
        "nist 800-53",
        "nist csf",
        "nist sp 800-171",
        "fedramp",
        "fisma",
        "itar",
        "cmmc",
        "csa",
        "csa star",
        "star",
        "aicpa",
        "ssae 18",
        "ssae 16",
        "ssae",
        "cis",
        "cis benchmarks",
        "owasp",
        "owasp top 10",
        "cobit",
        "itil",
        "eu",
        "european union",
    ];
    if standards_and_frameworks.contains(&lower.as_str()) {
        return true;
    }
    // Standards with version numbers: "ISO 27001:2022", "SOC 2 Type II", etc.
    if lower.starts_with("iso ")
        || lower.starts_with("iso/")
        || lower.starts_with("soc ")
        || lower.starts_with("nist ")
        || lower.starts_with("pci")
    {
        return true;
    }

    // Non-vendor organizations: charities, government bodies, standards bodies,
    // religious organizations, and similar entities that NER correctly identifies
    // as organizations but are not software/service vendors (BUG-003/010)
    let non_vendor_orgs = [
        "the salvation army",
        "salvation army",
        "red cross",
        "american red cross",
        "international red cross",
        "united nations",
        "world health organization",
        "who",
        "federal trade commission",
        "ftc",
        "securities and exchange commission",
        "sec",
        "department of defense",
        "dod",
        "department of homeland security",
        "dhs",
        "national security agency",
        "nsa",
        "government accountability office",
        "gao",
        "european commission",
        "international organization for standardization",
        "international electrotechnical commission",
        "national institute of standards and technology",
        "internet engineering task force",
        "ietf",
        "world wide web consortium",
        "w3c",
        "ieee",
    ];
    if non_vendor_orgs.contains(&lower.as_str()) {
        return true;
    }

    // ISO 639-1 language codes that NER misidentifies as organizations
    // (commonly found on internationalized Microsoft/Salesforce pages)
    let language_codes = [
        "ar", "bg", "bn", "ca", "cs", "cy", "da", "de", "el", "en", "es", "et", "eu", "fa", "fi",
        "fr", "ga", "gl", "gu", "he", "hi", "hr", "hu", "hy", "id", "is", "it", "ja", "ka", "kk",
        "km", "kn", "ko", "lb", "lo", "lt", "lv", "mk", "ml", "mn", "mr", "ms", "mt", "my", "ne",
        "nl", "no", "pa", "pl", "ps", "pt", "ro", "ru", "si", "sk", "sl", "so", "sq", "sr", "sv",
        "sw", "ta", "te", "th", "tl", "tr", "uk", "ur", "uz", "vi", "zh",
    ];
    if language_codes.contains(&lower.as_str()) {
        return true;
    }

    false
}

