        let divs: Vec<_> = html.select(&DIV_SELECTOR).collect();
        assert!(!divs.is_empty(), "DIV_SELECTOR should match");
        let all: Vec<_> = html.select(&ALL_ELEMENTS_SELECTOR).collect();
